UPDATE 
    HC_DEPT
SET 
    DEPT_NAME =  #{deptName}
    , DEPT_ENG_NAME =  #{deptEngName}
    , DEPT_STAT = #{deptStat}
    , DEPT_MOD_ID = #{deptModId}
    , DEPT_MOD_DT = SYSDATE()

    	, DEPT_CODE = #{deptCode}

WHERE
	1=1
	AND DEPT_ID = #{deptId}
	AND DEPT_STAT != 'delete'

    UPDATE 
	    HC_DEPT
	SET 
	    DEPT_STAT = #{deptStat}
